-- Canonical database schema for the Clash Royale winner-prediction project.
-- This file is the single source of truth for the relational schema and is
-- executed (idempotently) by scripts/database_connection.py::ensure_schema.
-- Keep column types here in sync with the data written by scripts/load_data.py.

CREATE TABLE IF NOT EXISTS "Clan" (
  "tag" VARCHAR PRIMARY KEY,
  "badgeId" INT
);

CREATE TABLE IF NOT EXISTS "Card" (
  "id" INT PRIMARY KEY
);

CREATE TABLE IF NOT EXISTS "Match" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "battleTime" TIMESTAMP,
  "arena_id" INT,
  "gameMode_id" INT,
  "tournamentTag" VARCHAR,
  "average_startingTrophies" DOUBLE PRECISION
);

CREATE TABLE IF NOT EXISTS "MatchPlayer" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "match_id" INT NOT NULL REFERENCES "Match" ("id") DEFERRABLE INITIALLY IMMEDIATE,
  "player_tag" VARCHAR,
  "clan_tag" VARCHAR REFERENCES "Clan" ("tag") DEFERRABLE INITIALLY IMMEDIATE,
  "is_winner" BOOLEAN NOT NULL,
  "startingTrophies" DOUBLE PRECISION,
  "elixir_average" DOUBLE PRECISION,
  "totalcard_level" INT,
  "troop_count" INT,
  "structure_count" INT,
  "spell_count" INT,
  "common_count" INT,
  "rare_count" INT,
  "epic_count" INT,
  "legendary_count" INT,
  "trophyChange" DOUBLE PRECISION,
  "crowns" DOUBLE PRECISION,
  "kingTowerHitPoints" DOUBLE PRECISION,
  "princessTowersHitPoints" DOUBLE PRECISION
);

CREATE TABLE IF NOT EXISTS "MatchPlayerCard" (
  "match_player_id" INT NOT NULL REFERENCES "MatchPlayer" ("id") DEFERRABLE INITIALLY IMMEDIATE,
  "card_id" INT NOT NULL REFERENCES "Card" ("id") DEFERRABLE INITIALLY IMMEDIATE,
  "card_level" INT,
  PRIMARY KEY ("match_player_id", "card_id")
);

COMMENT ON COLUMN "MatchPlayer"."is_winner" IS 'Target Variable (y) for prediction';
COMMENT ON COLUMN "MatchPlayer"."princessTowersHitPoints" IS 'Total HP of the standing princess towers (sum of the list-encoded source values, 0 when both are destroyed)';
